from collections import defaultdict
from heapq import heappush, heappop

N, M, P = map(int, input().split())

G = defaultdict(list)
for _ in range(M):
    a, b, c = map(int, input().split())
    G[a].append((b, c))

INF = 10**18
d = [INF] * (N + 1)
d[1] = 0
pq = [(0, 1)]
while pq:
    v = heappop(pq)[1]
    if d[v] < INF:
        for nv, cost in G[v]:
            if d[nv] > d[v] + cost:
                d[nv] = d[v] + cost
                heappush(pq, (d[nv], nv))

ans = -1
for i in range(1, N + 1):
    ans = max(ans, d[i] - P * i)

if ans < 0:
    print(-1)
else:
    print(ans)
